@dataclass(frozen=True)
class IssueOwnersActivityAlertStrategy(NotificationStrategy):
    """
    Strategy for sending activity alerts to Issue Owners.
    A bit different than that used for GroupEvent alerts, since determine_eligible_recipients
    cannot be used here, we don't have an event to parse.
    """

    group: Group

    def get_targets(self) -> list[NotificationTarget]:
        user_ids, team_ids = self.get_issue_owner_ids()

        if team_ids:
            members = OrganizationMemberTeam.objects.filter(team_id__in=team_ids).select_related(
                "organizationmember"
            )
            for member in members:
                uid = member.organizationmember.user_id
                if uid is not None:
                    user_ids.add(uid)

        if not user_ids:
            return []

        users = user_service.get_many_by_id(ids=list(user_ids))
        targets: list[NotificationTarget] = []
        for user in users:
            if not user.email:
                continue
            targets.append(
                GenericNotificationTarget(
                    provider_key=NotificationProviderKey.EMAIL,
                    resource_type=NotificationTargetResourceType.EMAIL,
                    resource_id=user.email,
                )
            )
        return targets

    def get_issue_owner_ids(self) -> tuple[set[int], set[int]]:
        """
        Returns a tuple of (user_ids, team_ids) based on the issue owners.
        If a GroupAssignee is set, it will be the only identifier returned.
        If not, it will return the identifiers of the GroupOwners.
        """
        user_ids: set[int] = set()
        team_ids: set[int] = set()

        assignee = GroupAssignee.objects.filter(group=self.group).first()
        if assignee is not None:
            if assignee.user_id is not None:
                user_ids.add(assignee.user_id)
            elif assignee.team_id is not None:
                team_ids.add(assignee.team_id)
            return user_ids, team_ids

        owners = GroupOwner.objects.filter(group=self.group).exclude(
            user_id__isnull=True, team_id__isnull=True
        )
        for owner in owners:
            if owner.user_id is not None:
                user_ids.add(owner.user_id)
            elif owner.team_id is not None:
                team_ids.add(owner.team_id)

        return user_ids, team_ids

        if group_ids:
            groups = list(Group.objects.filter(id__in=group_ids))
        else:
            groups = []

        self._groups_cache = groups
        return groups

    @groups.setter
    def groups(self, values: Sequence[Group] | None) -> None:
        self._groups_cache = values
        self._group_ids = [group.id for group in values] if values else None

    def for_group(self, group: Group) -> GroupEvent:
        return GroupEvent.from_event(self, group)


class GroupEvent(BaseEvent):
    group: Group

    def __init__(
        self,
        project_id: int,
        event_id: str,
        group: Group,
        data: NodeData,
        snuba_data: Mapping[str, Any] | None = None,
        occurrence: IssueOccurrence | None = None,
    ) -> None:
        super().__init__(project_id, event_id, snuba_data=snuba_data)
        self.group = group
        self.data = data
        self._occurrence = occurrence

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, GroupEvent):
            return False
        return other.event_id == self.event_id and other.group_id == self.group_id

    def __hash__(self) -> int:
        return hash((self.group_id, self.event_id))

    @property
    def group_id(self) -> int:
        # TODO: Including this as a shim for now. I think it makes sense to remove this helper,
        # since people may as well use `group.id` instead of `group_id`, but it breaks a lot of
        # compatibility with `Event`. Including this here for now so that we don't have to rewrite
        # the whole codebase at once.
        return self.group.id

    @group_id.setter
    def group_id(self, value: int | None) -> None:
        pass

    @property
    def data(self) -> NodeData:
        return self._data

    @data.setter
    def data(self, value: NodeData | Mapping[str, Any] | None) -> None:
        if isinstance(value, NodeData):
            self._data = value
        else:
            node_id = GroupEvent.generate_node_id(self.project_id, self.event_id)
            self._data = NodeData(node_id, data=value)

    @classmethod
    def from_event(cls, event: Event, group: Group) -> GroupEvent:
        group_event = cls(
            project_id=event.project_id,
            event_id=event.event_id,
            group=group,
            data=deepcopy(event.data),
            snuba_data=deepcopy(event._snuba_data),
        )
        if hasattr(event, "_project_cache"):
            group_event.project = event.project
        return group_event

    @property
    def occurrence(self) -> IssueOccurrence | None:
        if not self._occurrence and self.occurrence_id:
            self._occurrence = IssueOccurrence.fetch(self.occurrence_id, self.project_id)
            if self._occurrence is None:
                logger.error(
                    "Failed to fetch occurrence for event",
                    extra={"group_id": self.group_id, "occurrence_id": self.occurrence_id},
                )

        return self._occurrence

    @occurrence.setter
    def occurrence(self, value: IssueOccurrence | None) -> None:
        self._occurrence = value

    @property
    def occurrence_id(self) -> str | None:
        if self._occurrence:
            return self._occurrence.id

        column = self._get_column_name(Columns.OCCURRENCE_ID)
        if column in self._snuba_data:
            return cast(str, self._snuba_data[column])
        return None

    @cached_property
    def search_message(self) -> str:
        message = super().search_message
        # Include values from the occurrence in our search message as well, so that occurrences work
        # correctly in search.
        if self.occurrence is not None:
            message = augment_message_with_occurrence(message, self.occurrence)

        return message


def augment_message_with_occurrence(message: str, occurrence: IssueOccurrence) -> str:
    for attr in ("issue_title", "subtitle", "culprit"):
        value = getattr(occurrence, attr, "")
        if value and value not in message:
            value = force_str(value, errors="replace")
            message = f"{message} {value}"
    return message


